import java.io.File
fun main(args:Array<String>){val p = { x:Int,y:Int -> BrushPoint(x.toDouble(),y.toDouble()) };val points=listOf(500 to 520,450 to 450,390 to 395,320 to 370,250 to 370,180 to 390,130 to 450,120 to 520,155 to 585,220 to 635,300 to 650,380 to 620,440 to 570,500 to 520,560 to 465,620 to 410,700 to 370,770 to 380,830 to 420,870 to 480,875 to 545,845 to 610,790 to 660,720 to 675,650 to 655,585 to 610,540 to 560,500 to 520).map{p(it.first,it.second)};check(Brush.buildRoundedDrawingPath(listOf(p(0,0),p(100,0),p(100,100)),40.0)=="M 0 0 L 55 0 Q 100 0 100 45 L 100 100");val input=args.getOrNull(0)?:"assets/example.webp";val output=args.getOrNull(1)?:"generated/kotlin.svg";val svg=Brush.renderSvg(File(input).readBytes(),"image/webp",1000.0,1000.0,points,"🤝 best friends forever",BrushOptions(magicGradient=true));File(output).parentFile.mkdirs();File(output).writeText(svg);println("Wrote $output")}
